interface SortStrategy {
    void sort(int[] data);
    String getName();
}
class BubbleSort implements SortStrategy {
    @Override public void sort(int[] d) {
        for (int i = 0; i < d.length-1; i++)
            for (int j = 0; j < d.length-1-i; j++)
                if (d[j] > d[j+1]) { int t = d[j]; d[j] = d[j+1]; d[j+1] = t; }
    }
    @Override public String getName() { return "Bubble Sort"; }
}
class SelectionSort implements SortStrategy {
    @Override public void sort(int[] d) {
        for (int i = 0; i < d.length-1; i++) {
            int min = i;
            for (int j = i+1; j < d.length; j++) if (d[j] < d[min]) min = j;
            int t = d[i]; d[i] = d[min]; d[min] = t;
        }
    }
    @Override public String getName() { return "Selection Sort"; }
}
class Processor {
    SortStrategy strategy;
    Processor(SortStrategy s) { strategy = s; }
    void process(int[] data) {
        System.out.println("Using: " + strategy.getName());
        strategy.sort(data);
        for (int n : data) System.out.print(n + " ");
        System.out.println();
    }
}
public class Main {
    public static void main(String[] args) {
        new Processor(new BubbleSort()).process(new int[]{5,2,8,1,9});
        new Processor(new SelectionSort()).process(new int[]{5,2,8,1,9});
    }
}

